const BOT_TOKEN = '8723896780:AAFISWZwETo8fbK9srUzuZyh2e7OipRlr7g';

const msg = $('Telegram Trigger').first().json.message;
const fileId = msg.voice?.file_id || msg.audio?.file_id;
const mimeType = msg.voice?.mime_type || msg.audio?.mime_type || 'audio/ogg';
const telegramUser = msg.from?.first_name || 'Usuário';

if (!fileId) throw new Error('Nenhum file_id encontrado na mensagem');

// 1. Obter file_path
const infoRes = await fetch(`https://api.telegram.org/bot${BOT_TOKEN}/getFile?file_id=${fileId}`);
const infoJson = await infoRes.json();
if (!infoJson.ok) throw new Error('getFile falhou: ' + JSON.stringify(infoJson));
const filePath = infoJson.result.file_path;

// 2. Baixar o binário
const fileRes = await fetch(`https://api.telegram.org/file/bot${BOT_TOKEN}/${filePath}`);
if (!fileRes.ok) throw new Error('Download falhou: ' + fileRes.status);
const arrayBuffer = await fileRes.arrayBuffer();
const base64Audio = Buffer.from(arrayBuffer).toString('base64');

return [{ json: { base64Audio, mimeType, telegram_user: telegramUser } }];

